#include "qp/execution/slippage_model.hpp"
#include <cmath>
#include <stdexcept>
namespace qp::execution { Result<SlippageResult> NoSlippageModel::apply(const SlippageInput& in) const { if(!in.reference_price.is_positive()) return Err<SlippageResult>(Error{ErrorCode::InvalidArgument,"reference price must be positive"}); return Ok(SlippageResult{in.reference_price,0.0}); } FixedBpsSlippageModel::FixedBpsSlippageModel(BasisPoints b): bps_(b){ if(!std::isfinite(b.value)||b.value<0.0) throw std::invalid_argument("invalid slippage bps"); } Result<SlippageResult> FixedBpsSlippageModel::apply(const SlippageInput& in) const { if(!in.reference_price.is_positive()) return Err<SlippageResult>(Error{ErrorCode::InvalidArgument,"reference price must be positive"}); double delta=in.reference_price.value*bps_.value/10000.0; double px=in.side==OrderSide::Buy ? in.reference_price.value+delta : in.reference_price.value-delta; if(px<=0.0) return Err<SlippageResult>(Error{ErrorCode::InvalidArgument,"slippage produced non-positive fill price"}); return Ok(SlippageResult{Price{px}, std::abs(px-in.reference_price.value)*in.quantity.value}); } Result<SlippageResult> QuoteTouchSlippageModel::apply(const SlippageInput& in) const { if(!in.quote) return NoSlippageModel{}.apply(in); auto qok=in.quote->validate(); if(!qok) return Err<SlippageResult>(qok.error()); Price px = in.side==OrderSide::Buy ? in.quote->ask_price : in.quote->bid_price; return Ok(SlippageResult{px, std::abs(px.value-in.reference_price.value)*in.quantity.value}); } }
